     1→"use client";
     2→
     3→import { create } from "zustand";
     4→
     5→type MessagePart =
     6→  | { type: "text"; text: string }
     7→  | { type: "file"; url: string; mediaType: string; filename?: string };
     8→
     9→type SendMessageFn = (parts: MessagePart[]) => Promise<void>;
    10→
    11→type AgentChatStore = {
    12→  // Function to send a message to the agent
    13→  sendMessage: SendMessageFn | null;
    14→
    15→  // Register the send message function (called by ChatClient)
    16→  registerSendMessage: (fn: SendMessageFn | null) => void;
    17→
    18→  // Helper to send a text message (canvas selection is auto-injected by InputBar mechanism)
    19→  sendAgentMessage: (message: string) => Promise<void>;
    20→
    21→  // Helper to send a message with explicit image URL context
    22→  sendAgentMessageWithImage: (message: string, imageUrl: string) => Promise<void>;
    23→};
    24→
    25→export const useAgentChatStore = create<AgentChatStore>((set, get) => ({
    26→  sendMessage: null,
    27→
    28→  registerSendMessage: (fn) => set({ sendMessage: fn }),
    29→
    30→  sendAgentMessage: async (message: string) => {
    31→    const { sendMessage } = get();
    32→    if (!sendMessage) {
    33→      console.warn("Agent chat not ready. Cannot send message.");
    34→      return;
    35→    }
    36→    await sendMessage([{ type: "text", text: message }]);
    37→  },
    38→
    39→  sendAgentMessageWithImage: async (message: string, imageUrl: string) => {
    40→    const { sendMessage } = get();
    41→    if (!sendMessage) {
    42→      console.warn("Agent chat not ready. Cannot send message.");
    43→      return;
    44→    }
    45→    // Match InputBar's format exactly:
    46→    // 1. Text message (user's command)
    47→    // 2. File part (for visual context)
    48→    // 3. Text part with URL prefix (for tool URL extraction)
    49→    await sendMessage([
    50→      { type: "text", text: message },
    51→      { type: "file", url: imageUrl, mediaType: "image/*" },
    52→      { type: "text", text: `Canvas selection 1 URL: ${imageUrl}` },
    53→    ]);
    54→  },
    55→}));
    56→

