   282→      // Add media from completed tool calls to canvas
   283→      if (message.role === "assistant" && message.parts) {
   284→        for (const part of message.parts) {
   285→          // Type guard: check if part is a tool part with output
   286→          const isToolPart =
   287→            typeof part === "object" &&
   288→            part !== null &&
   289→            "type" in part &&
   290→            typeof part.type === "string" &&
   291→            part.type.startsWith("tool-") &&
   292→            "state" in part &&
   293→            part.state === "output-available" &&
   294→            "output" in part &&
   295→            part.output !== undefined &&
   296→            "toolCallId" in part &&
   297→            typeof part.toolCallId === "string";
   298→
   299→          if (!isToolPart) continue;
   300→
   301→          const toolCallId = part.toolCallId;
   302→          const output = part.output;
   303→
   304→          // Skip if we've already processed this tool call
