   317→              videoPollingData.predictionId,
   318→              "video-generation",
   319→              0, // index for single video
   320→              ".mp4", // Video extension
   321→            );
   322→            const s3Url = generateCloudFrontUrl(s3Key);
   323→
   324→            // Extend polling data with S3 URL
   325→            const extendedVideoPollingData = {
   326→              ...videoPollingData,
   327→              s3Url,
   328→            };
   329→
   330→            const baseMetadata: Record<string, unknown> = {
   331→              source: "agent-chat",
   332→              mediaType: "video",
   333→              toolCallId,
   334→              chatId: activeChatIdRef.current,
   335→              projectId,
   336→              createdAt: new Date().toISOString(),
   337→              model: modelSelectionRef.current.isAutoMode
   338→                ? "auto"
   339→                : modelSelectionRef.current.videoModel,
   340→            };
   341→
   342→            executeCommand({
   343→              type: "add",
   344→              mediaType: "video",
   345→              objectId: `${toolCallId}-0`, // Generate stable ID (videos with polling are typically single)
   346→              pollingData: extendedVideoPollingData,
   347→              metadata: baseMetadata,
   348→            }).catch((error: unknown) => {
   349→              console.error("Failed to add video with polling:", error);
   350→              // Remove from processed set on error so it can be retried
   351→              processedToolCallsRef.current.delete(toolCallId);
   352→            });
   353→            continue;
   354→          }
   355→
   356→          // Extract image polling data (images that need polling)
   357→          const imagePollingData = extractImagePollingData(output);
   358→          if (imagePollingData) {
   359→            // Generate S3 key/URL upfront using predictionId
   360→            const s3Key = generateS3KeyFromPredictionId(
   361→              imagePollingData.predictionId,
   362→              "image-generation", // Default toolName, can be enhanced later
   363→              0, // index for single image
   364→              ".webp", // Default extension
   365→            );
   366→            const s3Url = generateCloudFrontUrl(s3Key);
   367→
   368→            // Extend polling data with S3 URL (s3Key not needed for persistence)
   369→            const extendedPollingData = {
   370→              ...imagePollingData,
   371→              s3Url,
   372→            };
   373→
   374→            const baseMetadata: Record<string, unknown> = {
   375→              source: "agent-chat",
   376→              mediaType: "image",
   377→              toolCallId,
   378→              chatId: activeChatIdRef.current,
