   430→
   431→            Promise.all(addPromises).catch((error: unknown) => {
   432→              console.error("Failed to add media to canvas:", error);
   433→              // Remove from processed set on error so it can be retried
   434→              processedToolCallsRef.current.delete(toolCallId);
   435→            });
   436→          }
   437→        }
   438→      }
   439→    },
   440→    onError(error) {
   441→      console.error("Chat error:", error);
   442→      // Error will be displayed in the messages stream from server
