   444→  });
   445→
   446→  // Register sendMessage for external components (e.g., MediaNodeToolbar)
   447→  useEffect(() => {
   448→    type MessagePart =
   449→      | { type: "text"; text: string }
   450→      | { type: "file"; url: string; mediaType: string; filename?: string };
   451→
   452→    const wrappedSendMessage = async (parts: MessagePart[]) => {
