   511→    chatData?.messages,
   512→    setMessages,
   513→    activeChatId,
   514→    isOptimisticChat,
   515→    clearCanvasSelection,
   516→  ]);
   517→
   518→  // Dedupe messages by ID - ensures latest version wins during streaming updates with tool calls
   519→  // TODO: Uncomment this if we want to deduplicate messages
   520→  // const processedMessages = useMemo(() => {
   521→  //   const messageMap = new Map<string, UIMessage>();
   522→  //   for (const msg of messages) {
   523→  //     messageMap.set(msg.id, msg);
