   359→/**
   360→ * Renders message parts with intelligent grouping
   361→ * - Groups consecutive images into grids
   362→ * - Renders other parts individually
   363→ */
   364→export default function MessagePartRenderer({
   365→  parts,
   366→  debugToolUi = true,
   367→  onAddImageToCanvas,
   368→}: MessagePartRendererProps) {
   369→  if (!parts || parts.length === 0) {
   370→    return null;
   371→  }
   372→
   373→  const renderedElements: React.ReactNode[] = [];
   374→  let i = 0;
   375→
   376→  while (i < parts.length) {
   377→    const part = parts[i];
   378→
   379→    // Check if this is the start of an image sequence
   380→    // Handle both type: "image" (old) and type: "file" with image mediaType (new)
   381→    const isImage =
   382→      (part.type === "image" && part.image) ||
   383→      (part.type === "file" &&
   384→        part.mediaType?.startsWith("image/") &&
   385→        part.url);
   386→
   387→    if (isImage) {
   388→      const imageUrls: string[] = [];
   389→      const startIndex = i;
   390→
   391→      // Collect consecutive images
   392→      while (i < parts.length) {
   393→        const currentPart = parts[i];
   394→        const isCurrentImage =
   395→          (currentPart.type === "image" && currentPart.image) ||
   396→          (currentPart.type === "file" &&
   397→            currentPart.mediaType?.startsWith("image/") &&
   398→            currentPart.url);
   399→
   400→        if (!isCurrentImage) break;
   401→
   402→        const imageUrl =
   403→          currentPart.type === "image" ? currentPart.image : currentPart.url;
   404→        if (imageUrl) imageUrls.push(imageUrl);
   405→        i += 1;
   406→      }
   407→
   408→      // Render grouped images
   409→      renderedElements.push(renderImageGrid(imageUrls, startIndex, onAddImageToCanvas));
   410→    } else {
   411→      // Render non-image parts individually
   412→      const singlePart = renderSinglePart(part, i, debugToolUi);
   413→      if (singlePart) {
   414→        // Tools are already wrapped in MessageContent, so don't wrap again
   415→        const isTool = [
   416→          "tool-autoModelSuggest",
   417→          "tool-autoVideoModelSuggest",
   418→          "tool-GenerateImage",
   419→          "tool-GenerateVideo",
   420→          "tool-GenerateEditImage",
   421→          "tool-generateImageWithPolling",
   422→          "tool-generateVideoWithPolling",
   423→          "tool-generateAudio",
   424→          "tool-bgRemover",
   425→          "tool-imageResizer",
   426→          "tool-imageUpscaler",
   427→          "dynamic-tool",
   428→        ].includes(part.type);
   429→
   430→        if (isTool) {
   431→          renderedElements.push(singlePart);
   432→        } else {
   433→          renderedElements.push(
   434→            <MessageContent key={i}>{singlePart}</MessageContent>,
   435→          );
   436→        }
   437→      }
   438→      i += 1;
   439→    }
   440→  }
   441→
   442→  return <div className="space-y-2">{renderedElements}</div>;
   443→}
