   381→          // ID priority: responseMessage.id > continuationMessageId > new UUID
   382→          // This ensures multi-step tool executions share the same message ID
   383→          const messageId =
   384→            responseMessage.id || continuationMessageId || crypto.randomUUID();
   385→
   386→          const messageToSave: UIMessage = {
   387→            ...responseMessage,
   388→            id: messageId,
   389→          };
   390→
   391→          try {
   392→            await saveChatMessage({
   393→              message: messageToSave,
   394→              chatId: chat.id,
   395→              userId,
   396→            });
   397→            logger.info(
   398→              `Assistant message saved: ${messageToSave.id} (${messageToSave.parts.length} parts)`,
   399→            );
   400→          } catch (saveError) {
   401→            logger.error(
   402→              `Failed to save assistant message: ${saveError instanceof Error ? saveError.message : String(saveError)}`,
   403→            );
   404→          }
   405→        }
   406→      },
   407→    });
   408→  } catch (error) {
   409→    // Enhanced pre-stream error logging
   410→    const errorMessage =
   411→      error instanceof Error ? error.message : "Unknown error";
   412→    const stack = error instanceof Error ? error.stack : "no stack";
   413→    logger.error(
   414→      `Error in POST request (before streaming): error=${errorMessage}, requestId=${requestId}, stack=${stack}`,
   415→    );
   416→
   417→    // Update Langfuse trace with error
   418→    updateActiveObservation({
   419→      output: errorMessage,
   420→      level: "ERROR",
   421→    });
   422→
   423→    updateActiveTrace({
   424→      output: errorMessage,
   425→    });
   426→
   427→    trace.getActiveSpan()?.end();
   428→
   429→    try {
   430→      const textId = crypto.randomUUID();
   431→
   432→      const stream = createUIMessageStream<UIMessage>({
   433→        originalMessages: [message],
   434→        execute: ({ writer }) => {
   435→          writer.write({ type: "text-start", id: textId });
   436→          writer.write({
   437→            type: "text-delta",
   438→            id: textId,
   439→            delta:
   440→              "Sorry, I am not able to respond right now. Please try again later.",
   441→          });
   442→          writer.write({ type: "text-end", id: textId });
   443→        },
   444→      });
   445→
   446→      return createUIMessageStreamResponse({ stream });
   447→    } catch (streamError) {
   448→      const streamErrorMsg =
   449→        streamError instanceof Error
   450→          ? streamError.message
   451→          : String(streamError);
   452→      logger.error(
   453→        `Failed to create error stream: error=${streamErrorMsg}, requestId=${requestId}`,
   454→      );
   455→
   456→      // Fallback to plain text response if stream creation fails
   457→      return new Response(
   458→        JSON.stringify({
   459→          error:
   460→            "An error occurred while processing your request. Please try again.",
   461→        }),
   462→        {
   463→          status: 500,
   464→          headers: { "Content-Type": "application/json" },
   465→        },
   466→      );
   467→    }
   468→  }
   469→};
   470→
   471→// Wrap handler with Langfuse observe for automatic tracing
   472→// endOnExit: false keeps the observation open during streaming
   473→export const POST = observe(handler, {
   474→  name: "handle-agent-chat",
   475→  endOnExit: false,
   476→});
   477→
   478→function extractTextFromUiMessage(message: UIMessage): string | undefined {
   479→  return extractTextFromParts(message.parts);
   480→}
   481→
   482→function extractTextFromParts(parts: UIMessage["parts"]): string | undefined {
   483→  const chunks: string[] = [];
   484→  for (const part of parts) {
   485→    if (part.type === "text") {
   486→      chunks.push(part.text);
   487→    }
   488→  }
   489→  const text = chunks.join("");
   490→  return text.trim().length ? text : undefined;
   491→}
   492→
   493→function extractLatestUserTextFromUiMessages(messages: UIMessage[]): string | undefined {
   494→  for (let i = messages.length - 1; i >= 0; i -= 1) {
   495→    const msg = messages[i];
   496→    if (msg.role !== "user") continue;
   497→    const text = extractTextFromUiMessage(msg);
   498→    if (text) return text;
   499→  }
   500→  return undefined;
   501→}
   502→
   503→function summarizeParts(parts: UIMessage["parts"]): string {
   504→  const counts = new Map<string, number>();
   505→  for (const part of parts) {
   506→    counts.set(part.type, (counts.get(part.type) ?? 0) + 1);
   507→  }
   508→  const summary = [...counts.entries()]
   509→    .map(([type, count]) => `${type}:${count}`)
   510→    .join(", ");
   511→
   512→  return summary.length ? `parts(${summary})` : "parts(empty)";
   513→}
