     8→
     9→import type { Ratelimit } from "@upstash/ratelimit";
    10→import {
    11→  agentLimiter,
    12→  compareModeLimiter,
    13→  freeImgGenLimiter,
    14→  promptVariationLimiter,
    15→  sharedLimiter,
    16→} from "./lib/ratelimit";
    17→
    18→// TODO : Add Logging Here
    19→
    20→// Define rate-limited routes
    21→const rateLimitedRoutes = [
    22→  "/api/nebula-freeimage",
    23→  "/api/venus-9/v1",
    24→  "/api/compare/custom",
    25→  "/api/prompt-variation",
    26→  "/api/agents/*",
    27→];
    28→
    29→async function rateLimit(request: NextRequest) {
    30→  const path = request.nextUrl.pathname;
    31→
    32→  // Determine which limiter to use based on the path
    33→  let limiter: Ratelimit;
    34→  if (path === "/api/nebula-freeimage") {
    35→    limiter = freeImgGenLimiter;
    36→  } else if (path.startsWith("/api/venus-9")) {
    37→    limiter = sharedLimiter;
    38→  } else if (path === "/api/compare/custom") {
    39→    limiter = compareModeLimiter;
    40→  } else if (path.startsWith("/api/prompt-variation")) {
    41→    limiter = promptVariationLimiter; // Dedicated limiter for prompt variations
    42→  } else if (path.startsWith("/api/agents")) {
    43→    limiter = agentLimiter; // Dedicated limiter for agent
    44→  } else {
    45→    return null;
    46→  }
    47→
    48→  const ip = (await headers()).get("x-forwarded-for") || "127.0.0.1";
    49→  const { success, limit, reset, remaining } = await limiter.limit(ip);
    50→  if (!success) {
    51→    return new NextResponse("Rate limit exceeded", {
    52→      status: 429,
    53→      headers: {
    54→        "X-RateLimit-Limit": limit.toString(),
    55→        "X-RateLimit-Remaining": remaining.toString(),
    56→        "X-RateLimit-Reset": reset.toString(),
    57→      },
    58→    });
    59→  }
    60→
    61→  const response = NextResponse.next();
    62→
    63→  // Add rate limit headers to the response
    64→  response.headers.set("X-RateLimit-Limit", limit.toString());
    65→  response.headers.set("X-RateLimit-Remaining", remaining.toString());
    66→  response.headers.set("X-RateLimit-Reset", reset.toString());
    67→
    68→  return response;
    69→}
    70→
    71→export default clerkMiddleware(async (auth, req) => {
    72→  const { pathname } = req.nextUrl;
    73→
    74→  // Check if maintenance mode is enabled
    75→  const isMaintenance = env.IS_MAINTENANCE;
    76→
    77→  // If maintenance mode is enabled, redirect to maintenance page
    78→  if (isMaintenance) {
    79→    // Allow access to the maintenance page itself
    80→    if (pathname === "/maintenance") {
    81→      return NextResponse.next();
    82→    }
    83→
    84→    // Allow Next.js internal routes
    85→    if (pathname.startsWith("/_next/")) {
    86→      return NextResponse.next();
    87→    }
    88→
    89→    // Allow static assets (files with extensions)
    90→    if (FILE_EXTENSION_REGEX.test(pathname)) {
    91→      return NextResponse.next();
    92→    }
    93→
    94→    // Redirect all other routes to maintenance page
    95→    return NextResponse.redirect(new URL("/maintenance", req.url));
    96→  }
    97→
    98→  const { userId } = await auth();
    99→
   100→  // Set locale cookie
   101→  const response = NextResponse.next();
   102→
   103→  // For other protected routes, simply protect them without redirect
   104→  const isProtectedRoute = createRouteMatcher([
   105→    "/profile(.*)",
   106→    "/dashboard(.*)",
   107→    "/Profile(.*)",
   108→    "/admin(.*)",
   109→    "/inspiration(.*)",
   110→    "/image-editor(.*)",
   111→    "/superchat(.*)",
   112→    "/subscription(.*)",
   113→    "/legacy(.*)",
   114→    "/video-editor(.*)",
   115→    "/chat(.*)",
   116→    // Polling and status check routes
   117→    "/api/(.*)/prediction/(.*)",
   118→    "/api/agents/(.*)",
   119→  ]);
   120→
   121→  if (isProtectedRoute(req) && !userId) {
   122→    await auth.protect();
   123→  }
   124→
   125→  // Apply rate limiting for specific API routes
   126→  if (
   127→    rateLimitedRoutes.some((route) => req.nextUrl.pathname.startsWith(route))
   128→  ) {
   129→    const rateLimitResponse = await rateLimit(req);
   130→    if (rateLimitResponse) {
   131→      return rateLimitResponse;
   132→    }
   133→  }
   134→
   135→  return response;
   136→});
   137→
